SELECT SUM(capacity) AS total_capacity
FROM zones
WHERE building_id IS NOT NULL;

SELECT zone_id, num_green_rooms 
FROM zone_color_counts 
WHERE num_green_rooms > 0;

SELECT zone_id, zone_description
FROM zones
WHERE area > (SELECT AVG(area) FROM zones);

SELECT MAX(z.capacity) AS max_capacity
FROM zones z
WHERE z.building_id = 1;

SELECT 
  (SELECT COUNT(zone_id) FROM zones) AS total_zones,
  (SELECT AVG(usage_duration) FROM zone_usage) AS average_usage_duration;

SELECT z.zone_id, z.zone_description, rc.num_yellow_rooms
FROM zones z
JOIN zone_color_counts rc ON z.zone_id = rc.zone_id;

SELECT zone_id, num_green_rooms, num_yellow_rooms
FROM zone_color_counts
WHERE num_green_rooms > num_yellow_rooms;

SELECT zone_id
FROM zones
WHERE current_occupancy = (SELECT MAX(current_occupancy) FROM zones);
